// // Asynchronous reset synchronizes the flip-flop's state on the falling edge of rst_n
module DFF_1bit(
   input                clk ,
   input                rst_n,
   input                D,

   output reg           Q  
);
    always@(posedge clk or negedge rst_n)begin
        if(!rst_n) Q <= 1'b0;
        else Q <= D;
    end
endmodule
